class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_pieces()
        self.turn = 'white'

    def initialize_pieces(self):
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 0:
                    self.board[i][j] = Piece(color='black')

