    def move_piece(self, move, color):
        from_pos, to_pos = move
        piece = self.board[from_pos[0]][from_pos[1]]
        if piece and piece.color == color:
            row_diff = to_pos[0] - from_pos[0]
            col_diff = abs(to_pos[1] - from_pos[1])

            if (row_diff == 1 and col_diff == 1) or (row_diff == 2 and col_diff == 2):
                self.board[to_pos[0]][to_pos[1]] = piece
                self.board[from_pos[0]][from_pos[1]] = None

                if row_diff == 2:
                    captured_piece = self.board[(from_pos[0] + to_pos[0]) // 2][(from_pos[1] + to_pos[1]) // 2]
                    if captured_piece is not None and (abs(from_pos[0] - to_pos[0]) == 2) and (abs(from_pos[1] - to_pos[1]) == 2):
