                self.switch_turn()
                return True

        return False

    def switch_turn(self):
        self.turn = 'black' if self.turn == 'white' else 'white'

    def check_winner(self):
        white_count = sum(1 for row in self.board for cell in row if cell and cell.color == 'white')
        black_count = sum(1 for row in self.board for cell in row if cell and cell.color == 'black')

        return white_count == 0 or black_count == 0

    def is_draw(self):
